'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneBadgeProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    maxSize?: number;
    defaultImage?: string;
    size?: 'sm' | 'md' | 'lg';
}

export function AvatarDropzoneBadge({
    className,
    onFileSelect,
    maxSize = 5 * 1024 * 1024,
    defaultImage,
    size = 'md',
}: AvatarDropzoneBadgeProps) {
    return (
        <SingleImageDrop
            variant="badge"
            size={size}
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            showStatusBadge={true}
            showProgress={true}
            showRemoveButton={false}
            className={className}
        />
    );
}
